class Solution {
public:
int solve(string s, int k) {
	int maxLength = 0;
	int i = 0;
	int j = 0;
	vector<int> dp;
	dp.push_back(0);
	while (i < s.length()) {
		while (j < s.length()) {
			if (s[i] != s[j]) {
				if (k > 0) {
					k--;
				}else {
					break;
				}
			}
			j++;
		}
		maxLength = max(maxLength, j - i);
		dp.push_back(maxLength);
		i = j;
	}
	return dp.back();
}
};

